"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { useState } from "react";
import { getStoredUser } from "../lib/mockAuth";

export default function Login() {
  const router = useRouter();
  const [form, setForm] = useState({
    email: "",
    password: "",
  });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleChange = (event) => {
    setForm((current) => ({
      ...current,
      [event.target.name]: event.target.value,
    }));

    if (error) {
      setError("");
    }
    if (success) {
      setSuccess("");
    }
  };

  const handleSubmit = async (event) => {
    event.preventDefault();

    if (!form.email.trim() || !form.password.trim()) {
      setError("Please fill in both email and password.");
      return;
    }

    const trimmedEmail = form.email.trim().toLowerCase();
    const storedUser = getStoredUser();

    if (!storedUser) {
      setError("No account found. Please sign up first.");
      return;
    }

    if (storedUser.email !== trimmedEmail || storedUser.password !== form.password) {
      setError("Invalid email or password.");
      return;
    }

    setIsSubmitting(true);
    setSuccess(`Welcome back, ${storedUser.name}. Redirecting...`);

    window.setTimeout(() => {
      setIsSubmitting(false);
      router.push("/");
    }, 700);
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-[linear-gradient(180deg,var(--grn-xlight)_0%,var(--wh)_100%)] px-8 py-14 sm:px-12 sm:py-20">
      <div className="m-4 w-full max-w-md rounded-[28px] border border-[var(--brd)] bg-white px-8 py-10 shadow-[0_24px_60px_rgba(39,80,10,0.12)] sm:m-6 sm:px-10 sm:py-12">
        <p className="text-center text-xs font-medium uppercase tracking-[0.18em] text-[var(--grn)]">
          Member Access
        </p>
        <h2 className="mt-4 text-center text-3xl font-semibold text-[var(--blk)]">
          Login
        </h2>
        <p className="mt-4 text-center text-sm leading-7 text-[var(--txt2)]">
          Sign in with the account you created on signup.
        </p>

        <form onSubmit={handleSubmit} className="mt-10 space-y-6">
          <div className="space-y-2.5">
            <label htmlFor="login-email" className="block text-sm font-medium text-[var(--txt)]">
              Email
            </label>
            <input
              id="login-email"
              type="email"
              name="email"
              placeholder="Enter your email"
              value={form.email}
              onChange={handleChange}
              className="w-full rounded-xl border border-[var(--brd)] bg-[var(--gry)] px-4 py-3 text-sm outline-none transition focus:border-[var(--grn)] focus:bg-white"
            />
          </div>

          <div className="space-y-2.5">
            <label htmlFor="login-password" className="block text-sm font-medium text-[var(--txt)]">
              Password
            </label>
            <input
              id="login-password"
              type="password"
              name="password"
              placeholder="Enter your password"
              value={form.password}
              onChange={handleChange}
              className="w-full rounded-xl border border-[var(--brd)] bg-[var(--gry)] px-4 py-3 text-sm outline-none transition focus:border-[var(--grn)] focus:bg-white"
            />
          </div>

          {error ? (
            <p className="text-sm text-red-600">{error}</p>
          ) : null}

          {success ? (
            <p className="text-sm text-[var(--grn-dark)]">{success}</p>
          ) : null}

          <button
            type="submit"
            disabled={isSubmitting}
            className="mt-2 w-full rounded-xl bg-[var(--grn)] py-3.5 text-sm font-medium text-white transition hover:bg-[var(--grn-acc)] disabled:cursor-not-allowed disabled:opacity-70"
          >
            {isSubmitting ? "Signing In..." : "Login"}
          </button>
        </form>

        <p className="mt-8 text-center text-sm leading-7 text-[var(--txt2)]">
          Don&apos;t have an account?{" "}
          <Link
            href="/signup"
            className="font-medium text-[var(--grn)] hover:text-[var(--grn-acc)]"
          >
            Signup
          </Link>
        </p>
      </div>
    </div>
  );
}
